import React from 'react'

export default function ErrorBoundary() {
  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      height: '100vh',
      textAlign: 'center',
      padding: '20px',
      background: '#0b1222'
    }}>
      <h1 style={{ fontSize: '48px', color: '#e63946', marginBottom: '16px' }}>Oops!</h1>
      <h2 style={{ fontSize: '20px', color: '#e2ecf7', marginBottom: '16px' }}>Algo deu errado.</h2>
      <p style={{ color: '#7b96b8', marginBottom: '32px', maxWidth: '400px' }}>
        Ocorreu um erro inesperado. Por favor, tente recarregar a página ou entre em contato com o suporte se o problema persistir.
      </p>
      <button 
        onClick={() => window.location.href = '/dashboard'}
        style={{
          padding: '12px 24px',
          background: '#1a2d4a',
          color: '#e2ecf7',
          border: '1px solid #4895ef',
          borderRadius: '8px',
          fontWeight: 600,
          cursor: 'pointer'
        }}
      >
        Recarregar Aplicação
      </button>
    </div>
  )
}
